55	const BASE_PREMIUM: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	};
62	
63	const COMPONENT_PRICE = 25;
64	const BLOCK_SIZE = 3;
65	const BLOCK_PRICE = 60;
66	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
67	
68	const INSURANCE_VALUE: Record<string, number> = {
69	  sword: 1000,
70	  amulet: 600,
71	  staff: 800,
72	  potion: 400,
73	};
74	const COMPONENT_INSURANCE_VALUE = 250;
75	
76	const DEDUCTIBLE = 100;
77	const CAP_MULTIPLIER = 2;
78	
79	const INITIAL_ASSESSMENT_RATE = 0.1;
80	const CURSE_SURCHARGE_RATE = 0.5;
81	const HIGH_ENCHANTMENT_RATE = 0.3;
82	const HIGH_ENCHANTMENT_THRESHOLD = 5;
83	const LOYALTY_DISCOUNT_RATE = 0.2;
84	const LOYALTY_YEARS_THRESHOLD = 2;
85	const FOLLOWUP_DISCOUNT_RATE = 0.15;
86	const PROCESSING_FEE = 5;
87	const FLOAT_PRECISION_DIGITS = 6;
88	
89	const itemOwnBase = (item: Item): number => {
90	  return COMPONENT_TYPES.has(item.type)
91	    ? COMPONENT_PRICE
92	    : BASE_PREMIUM[item.type];
93	};
94	
95	const itemSurcharge = (item: Item): number => {
96	  const own = itemOwnBase(item);
97	  const curse = item.cursed ? CURSE_SURCHARGE_RATE * own : 0;
98	  const highEnchantment =
99	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
100	      ? HIGH_ENCHANTMENT_RATE * own
101	      : 0;
102	  return curse + highEnchantment;
103	};
104	
105	const componentBase = (count: number): number => {
106	  return count === BLOCK_SIZE ? BLOCK_PRICE : count * COMPONENT_PRICE;
107	};
108	
109	const countByType = (items: Item[]): Map<string, number> => {
110	  const counts = new Map<string, number>();
111	  for (const item of items) {
112	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
113	  }
114	  return counts;
115	};
116	
117	const itemBaseTotal = (items: Item[]): number => {
118	  let total = 0;
119	  for (const [type, count] of countByType(items)) {
120	    total += COMPONENT_TYPES.has(type)
121	      ? componentBase(count)
122	      : BASE_PREMIUM[type] * count;
123	  }
124	  return total;
125	};
126	
127	const quotePremium = (
128	  step: QuoteStep,
129	  customer: Customer,
130	  isFollowUp: boolean,
131	): number => {
132	  const policyBase = itemBaseTotal(step.items);
133	  const surcharges = step.items.reduce(
134	    (sum, item) => sum + itemSurcharge(item),
135	    0,
136	  );
137	  const initialAssessment = INITIAL_ASSESSMENT_RATE * policyBase;
138	  const loyaltyDiscount =
139	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
140	      ? LOYALTY_DISCOUNT_RATE * policyBase
141	      : 0;
142	  const followUpDiscount = isFollowUp ? FOLLOWUP_DISCOUNT_RATE * policyBase : 0;
143	  const premium =
144	    policyBase +
145	    surcharges +
146	    initialAssessment -
147	    loyaltyDiscount -
148	    followUpDiscount +
149	    PROCESSING_FEE;
150	  return Math.ceil(Number(premium.toFixed(FLOAT_PRECISION_DIGITS)));
151	};
152	
153	interface Policy {
154	  items: Item[];
155	  remainingCap: number;
156	}
157	
158	const itemInsuranceValue = (item: Item): number => {
159	  return COMPONENT_TYPES.has(item.type)
160	    ? COMPONENT_INSURANCE_VALUE
161	    : INSURANCE_VALUE[item.type];
162	};
163	
164	const insuranceSum = (items: Item[]): number => {
165	  return items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
166	};
167	
168	const damagePayout = (amount: number): number => {
169	  return Math.max(0, amount - DEDUCTIBLE);
170	};
171	
172	const claimResult = (step: ClaimStep, policies: Policy[]): ClaimResult => {
173	  const policy = policies[step.policy];
174	  const requested = step.incident.damages.reduce(
175	    (sum, damage) => sum + damagePayout(damage.amount),
176	    0,
177	  );
178	  const payout = Math.min(requested, policy.remainingCap);
179	  policy.remainingCap -= payout;
180	  return { payout, remainingCap: policy.remainingCap };
181	};
182	
183	export const runScenario = (scenario: Scenario): ScenarioResult => {
184	  const policies: Policy[] = [];
185	  let quotesSeen = 0;
186	  const results = scenario.steps.map((step, index): Result => {
187	    if (step.op === "claim") {
188	      return claimResult(step, policies);
189	    }
190	    const isFollowUp = quotesSeen >= 1;
191	    quotesSeen += 1;
192	    policies[index] = {
193	      items: step.items,
194	      remainingCap: CAP_MULTIPLIER * insuranceSum(step.items),
195	    };
196	    return { premium: quotePremium(step, scenario.customer, isFollowUp) };
197	  });
198	  return { results };
199	};
